import{_ as t,o,c as n,a2 as i}from"./chunks/framework.CHeM0PsO.js";const p=JSON.parse('{"title":"RFC 0011 — Icon system (Lucide)","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0011-icon-system.md","filePath":"rfcs/0011-icon-system.md"}'),s={name:"rfcs/0011-icon-system.md"};function a(r,e,d,c,l,h){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-0011-—-icon-system-lucide" tabindex="-1">RFC 0011 — Icon system (Lucide) <a class="header-anchor" href="#rfc-0011-—-icon-system-lucide" aria-label="Permalink to &quot;RFC 0011 — Icon system (Lucide)&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Design system (<code>packages/ui</code>) — a new <code>Icon</code> component + a generated SVG set; runtime chrome; <code>PluginTile</code>/sidebar plugin-icon wiring; <code>docs/design-system.md</code> + <code>docs/plugin-development.md</code><br><strong>Incorporated into plan:</strong> Yes — <strong>Task 0.5.18</strong> (decision-log row in SRS §6). The <code>&lt;Icon&gt;</code> component, the generated zero-dependency SVG set, and the chrome adoption + plugin-icon wiring land in that task.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Adopt <strong>Lucide</strong> (lucide.dev) as Sovereign&#39;s icon language. Rather than depend on <code>lucide-react</code> at runtime, <strong>generate a curated set of inline SVG React components from Lucide into the design system</strong> and expose them behind a Sovereign <strong><code>&lt;Icon&gt;</code></strong> component. The published package ships plain SVGs + the wrapper — <strong>zero runtime or peer dependency</strong>. The ad-hoc monograms/emoji in the chrome are replaced with <code>&lt;Icon&gt;</code>, and the plugin manifest <code>icon.svg</code> (plugin <em>identity</em>) is finally wired into the UI.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>There is <strong>no icon system</strong> today. UI-affordance icons are improvised:</p><ul><li>the home link renders the monogram <code>&quot;S&quot;</code>;</li><li>Console renders the <strong><code>⚙</code> emoji</strong> (which looks different on every OS);</li><li>plugin tiles render a two-letter <strong>monogram</strong>; and</li><li>there is <strong>no icon dependency</strong> anywhere in the repo.</li></ul><p>Tellingly, the platform&#39;s own hand-drawn plugin icon (<code>plugins/launcher/icon.svg</code>) is already <code>viewBox=&quot;0 0 24 24&quot; fill=&quot;none&quot; stroke=&quot;currentColor&quot; stroke-width=&quot;2&quot;</code> — <strong>Lucide&#39;s exact convention</strong>. Adopting Lucide formalizes an aesthetic the project is already hand-rolling, and the manifest <code>icon</code> field (currently parsed but rendered as a monogram in <code>PluginTile</code>) finally gets used.</p><h2 id="why-lucide" tabindex="-1">Why Lucide <a class="header-anchor" href="#why-lucide" aria-label="Permalink to &quot;Why Lucide&quot;">​</a></h2><ul><li><strong>License:</strong> ISC (permissive) — compatible with the AGPL core, and <strong>bundled</strong> (no CDN/external fetch), so it respects NFR-02 (no external dependency for core) and the no-telemetry stance.</li><li><strong>Aesthetic:</strong> stroke-based <code>24×24</code> <code>currentColor</code> icons match the <strong>monochrome v1 identity</strong> and inherit <code>--sv-</code> color tokens for free (<code>currentColor</code> → <code>--sv-color-text-*</code>).</li><li><strong>Coverage &amp; upkeep:</strong> ~1,500 consistent, actively maintained icons (the Feather successor).</li></ul><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>No icon library</strong> in any <code>package.json</code> or the pnpm catalog.</li><li>Chrome glyphs live in <code>runtime/app/(platform)/layout.tsx</code> (monogram <code>S</code>, <code>⚙</code> emoji, two-letter monograms).</li><li>The manifest <code>icon</code> field is validated; <code>PluginTile</code> (<code>runtime/app/(platform)/(plugins)/launcher/_components/PluginTile.tsx</code>) parses but does not render it (monogram fallback).</li><li><strong>Design-system constraints</strong> (CLAUDE.md, <code>docs/design-system.md</code>): &quot;React + CSS Modules — <strong>zero extra dependencies</strong>&quot;; &quot;No Tailwind, no third-party component framework&quot;; monochrome identity; components reference <code>--sv-*</code> tokens only; RSC-safe; the package is the published contract.</li><li>PWA install icons (<code>runtime/public/icons/</code>) are a separate concern, untouched.</li></ul><h2 id="proposed-design-deferred-—-this-rfc-settles-the-contract" tabindex="-1">Proposed design (deferred — this RFC settles the contract) <a class="header-anchor" href="#proposed-design-deferred-—-this-rfc-settles-the-contract" aria-label="Permalink to &quot;Proposed design (deferred — this RFC settles the contract)&quot;">​</a></h2><h3 id="_1-vendored-generated-subset-—-zero-runtime-dependency" tabindex="-1">1. Vendored/generated subset — zero runtime dependency <a class="header-anchor" href="#_1-vendored-generated-subset-—-zero-runtime-dependency" aria-label="Permalink to &quot;1. Vendored/generated subset — zero runtime dependency&quot;">​</a></h3><p>Lucide is the <strong>source of truth</strong>, not a runtime dependency. A curated <strong>name list</strong> feeds a small <strong>generation script</strong> (a <code>pnpm</code> script) that emits inline, RSC-safe SVG React components from Lucide into the design system (<code>src/components/Icon/icons/</code>). <code>lucide</code> is a <strong>devDependency</strong> used only by that script; the <strong>published package ships the generated SVGs + the <code>&lt;Icon&gt;</code> wrapper</strong> — no runtime or peer dependency. This honors the &quot;zero extra dependencies&quot; principle and minimizes supply-chain surface (consistent with RFC 0008&#39;s hardening ethos). A <code>NOTICE</code> retains Lucide&#39;s ISC attribution.</p><p>Adding an icon = add a name to the list and regenerate. A chrome/console UI needs <strong>dozens</strong>, not 1,500 — so the set stays small and intentional.</p><h3 id="_2-the-icon-component" tabindex="-1">2. The <code>&lt;Icon&gt;</code> component <a class="header-anchor" href="#_2-the-icon-component" aria-label="Permalink to &quot;2. The `&lt;Icon&gt;` component&quot;">​</a></h3><p>Proposed API (final shape is an open question):</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Icon</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;home&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> size</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;md&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> aria-label</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Home&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Icon</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;settings&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> aria-hidden</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// decorative</span></span></code></pre></div><ul><li><code>name</code> is a <strong>typed union</strong> of the curated icon names (tree-shakeable; unknown names fail typecheck).</li><li>Size and color bind to <code>--sv-</code> tokens — a default size token (e.g. <code>--sv-icon-size-*</code>) and <code>currentColor</code> for color, so an icon recolors with its surrounding text token and themes for free.</li><li><strong>Accessibility:</strong> decorative icons set <code>aria-hidden</code>; meaningful icons require <code>aria-label</code>.</li><li><strong>RSC-safe</strong> — pure presentational SVG, no client JS, no hardcoded values (tokens only, per the design-system rule).</li></ul><h3 id="_3-affordance-vs-identity-—-an-explicit-split" tabindex="-1">3. Affordance vs identity — an explicit split <a class="header-anchor" href="#_3-affordance-vs-identity-—-an-explicit-split" aria-label="Permalink to &quot;3. Affordance vs identity — an explicit split&quot;">​</a></h3><ul><li><strong>UI-affordance icons</strong> (home, settings/gear, chevron, close, menu, …) → Lucide <code>&lt;Icon&gt;</code>.</li><li><strong>Plugin-identity icons</strong> → the <strong>author-supplied manifest <code>icon.svg</code></strong>, wired into <code>PluginTile</code> and the sidebar, with the monogram as the fallback when a plugin ships no icon. Guidance (not enforced): plugin authors should draw Lucide-style <code>24×24</code> stroke icons so third-party plugins sit visually with the platform.</li></ul><h3 id="_4-security-—-plugin-svgs-are-untrusted" tabindex="-1">4. Security — plugin SVGs are untrusted <a class="header-anchor" href="#_4-security-—-plugin-svgs-are-untrusted" aria-label="Permalink to &quot;4. Security — plugin SVGs are untrusted&quot;">​</a></h3><p>A plugin&#39;s <code>icon.svg</code> is third-party content. It must be rendered via <code>&lt;img src&gt;</code> (or sanitized) — <strong>never</strong> injected with <code>dangerouslySetInnerHTML</code>, which would be an SVG/XSS vector. This ties into RFC 0008 (the platform must not execute untrusted markup).</p><h3 id="_5-adoption-in-the-chrome-this-rfc-s-first-use" tabindex="-1">5. Adoption in the chrome (this RFC&#39;s first use) <a class="header-anchor" href="#_5-adoption-in-the-chrome-this-rfc-s-first-use" aria-label="Permalink to &quot;5. Adoption in the chrome (this RFC&#39;s first use)&quot;">​</a></h3><p>Replace the <code>S</code> home monogram and the <code>⚙</code> Console emoji (and other chrome glyphs) with <code>&lt;Icon&gt;</code>; keep the account avatar&#39;s image/monogram (that is identity, not an affordance). Then wire plugin <code>icon.svg</code> into <code>PluginTile</code>/ sidebar.</p><h2 id="impact-when-accepted-deferred" tabindex="-1">Impact when accepted (deferred) <a class="header-anchor" href="#impact-when-accepted-deferred" aria-label="Permalink to &quot;Impact when accepted (deferred)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where</th><th>Change</th></tr></thead><tbody><tr><td>Design system (<code>packages/ui</code>)</td><td>New <code>Icon</code> component + generated icons dir + generation script + <code>lucide</code> <strong>devDependency</strong> + ISC <code>NOTICE</code>; <code>src/index</code> export; <strong>minor</strong> bump.</td></tr><tr><td>Runtime chrome</td><td><code>runtime/app/(platform)/layout.tsx</code> — replace <code>S</code> / <code>⚙</code> with <code>&lt;Icon&gt;</code>.</td></tr><tr><td>Launcher / sidebar</td><td><code>PluginTile</code> + sidebar render the plugin <code>icon.svg</code> (monogram fallback).</td></tr><tr><td>Docs</td><td><code>docs/design-system.md</code> (Icon section + token binding) and <code>docs/plugin-development.md</code> (Icon usage + plugin-icon guidance).</td></tr></tbody></table><p>Not a manifest field, permission, SDK surface, or env var → <code>docs-parity.test.ts</code> is unaffected.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong><code>lucide-react</code> as a peer dependency + wrapper.</strong> Full set on tap and tree-shakeable, but adds a dependency to the <strong>published contract</strong> that every consumer must install. Rejected in favour of zero-dep vendoring (the design-system principle + the maintainer&#39;s preference for plain SVGs).</li><li><strong><code>lucide-react</code> bundled as a hard runtime dependency.</strong> Same objection, and worse (bundled into the contract).</li><li><strong>Lucide in the runtime only (not the design system).</strong> No shared <code>&lt;Icon&gt;</code> primitive for plugin developers; icon usage fragments. Rejected.</li><li><strong>Keep monograms/emoji.</strong> Inconsistent and OS-dependent. Rejected.</li><li><strong>Other icon sets</strong> (Heroicons, Phosphor, Feather). Lucide chosen for the aesthetic match to the existing <code>icon.svg</code>, active maintenance, and the ISC license.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong><code>&lt;Icon&gt;</code> API</strong> — single <code>name</code> union (proposed) vs per-icon named exports (<code>&lt;HomeIcon/&gt;</code>) vs both.</li><li><strong>Initial curated icon list</strong> — the starting set for the chrome + Console.</li><li><strong>Plugin <code>icon.svg</code> rendering</strong> — <code>&lt;img&gt;</code> vs sanitized inline (security).</li><li><strong>Offer the curated set to plugin devs?</strong> Or is <code>&lt;Icon&gt;</code> chrome/Console-only.</li><li><strong>Size token</strong> — introduce <code>--sv-icon-size-*</code>, or reuse spacing/font tokens.</li><li><strong>Generation tooling location</strong> — <code>scripts/</code> vs inside the design-system package.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; Lucide via a generated zero-dependency SVG set behind <code>&lt;Icon&gt;</code>.</td></tr><tr><td>1.0</td><td>Jun 2026</td><td>Accepted; incorporated into the build plan (Task 0.5.18) and a decision-log row.</td></tr></tbody></table>',36)])])}const u=t(s,[["render",a]]);export{p as __pageData,u as default};
